def resource_path(relative: str) -> str:
    """Return absolute path to a bundled resource."""
    if getattr(sys, "frozen", False) and hasattr(sys, "_MEIPASS"):
        return os.path.join(sys._MEIPASS, relative)
    return os.path.join(os.path.dirname(os.path.abspath(__file__)), relative)


def _run(cmd, **kwargs):
    """subprocess.run wrapper — suppresses console window on Windows."""
    if sys.platform == "win32":
        kwargs.setdefault("creationflags", subprocess.CREATE_NO_WINDOW)
    return subprocess.run(cmd, **kwargs)


# ── Embedded icon (base64 PNG per size) ───────────────────────────────────────
# Generated by generate_icon.py — embedded so no file-path lookup needed at runtime.
# Option B icon — two film strips + scissors (auto-generated)
ICON_DATA = {
    256: '',
    128: '',
    64: '',
    48: '',
    32: '',
    16: '',
}


def app_icon() -> QIcon:
    """
    Build the app icon entirely from embedded base64 PNG data.
    Each size is decoded and written to a temp PNG file, then loaded
    into a QPixmap. This bypasses all path/backslash/platform issues
    that cause QIcon(path) to silently return null on Windows.
    """
    import base64 as _b64, os as _os, tempfile as _tmp
    from PyQt6.QtGui import QPixmap

    icon = QIcon()
    for size, data in ICON_DATA.items():
        raw = _b64.b64decode(data)
        # Write to temp PNG then load — most reliable cross-platform method
        fd, tmp = _tmp.mkstemp(suffix=f"_{size}.png")
        try:
            with _os.fdopen(fd, "wb") as fh:
                fh.write(raw)
            pm = QPixmap(tmp)
            if not pm.isNull():
                icon.addPixmap(pm)
        except Exception:
            pass
        finally:
            try: _os.unlink(tmp)
            except: pass

    return icon

VIDEO_EXTENSIONS = (".mp4", ".mkv", ".avi", ".mov", ".ts", ".m2ts", ".wmv")

def fmt_time(seconds: float) -> str:
    h = int(seconds // 3600)
    m = int((seconds % 3600) // 60)
    s = seconds % 60
    return f"{h}:{m:02d}:{s:05.2f}" if h > 0 else f"{m:02d}:{s:05.2f}"

def fmt_size(bytes_val: float) -> str:
    """Human-readable file size."""
    for unit in ("B", "KB", "MB", "GB"):
        if bytes_val < 1024:
            return f"{bytes_val:.1f} {unit}"
        bytes_val /= 1024
    return f"{bytes_val:.1f} TB"

def estimate_segment_size(job, seg_duration: float, cut_mode: str, crf: int) -> str:
    """
    Estimate output file size for one segment.

    Stream copy / keyframe snap:
      Size scales linearly with duration from the source bitrate.

    Accurate re-encode:
      CRF-based estimate.  CRF 18 ~ 90% of source bitrate, CRF 23 ~ 60%,
      CRF 28 ~ 35%, CRF 51 ~ 5%.  Uses a simple exponential curve.

    Smart encode:
      Only the first ~5 seconds are re-encoded; the rest is stream copy.
      Treated as stream copy for estimation purposes.
    """
    if job.duration <= 0 or job.file_size_bytes <= 0:
        return "? MB"

    source_bps  = job.file_size_bytes / job.duration   # bytes per second
    seg_bytes   = source_bps * seg_duration

    if cut_mode in ("accurate",):
        # Rough CRF quality factor: CRF 18 -> 0.9x, CRF 23 -> 0.6x, CRF 28 -> 0.35x
        import math
        factor = max(0.05, 0.9 * math.exp(-0.05 * max(0, crf - 18)))
        seg_bytes *= factor

    return fmt_size(seg_bytes)

def detect_episode_range(filename: str):
    """
    Detect a multi-episode filename pattern like S01E01-E02 or S02E03E04.

    Returns a list of episode tags in order, e.g. ["S01E01", "S01E02"],
    or an empty list if no pattern is found.

    Supports formats:
      S01E01-E02          -> ["S01E01", "S01E02"]
      S01E01E02           -> ["S01E01", "S01E02"]
      S01E01-E02-E03      -> ["S01E01", "S01E02", "S01E03"]
      2x01-02             -> ["2x01", "2x02"]
    """
    import re as _re
    stem = Path(filename).stem

    # Pattern 1: S##E##-E## or S##E##E##  (most common)
    m = _re.match(
        r'(?i)(.*?)(S\d+)(E\d+)((?:[-]?E\d+)+)(.*)',
        stem
    )
    if m:
        prefix   = m.group(1)
        season   = m.group(2).upper()
        first_ep = m.group(3).upper()
        rest     = m.group(4).upper()
        suffix   = m.group(5)

        # Parse all subsequent ep tags
        extra_eps = _re.findall(r'E(\d+)', rest)
        first_num = int(_re.search(r'\d+', first_ep).group())

        tags = [f"{season}{first_ep}"]
        for ep_str in extra_eps:
            tags.append(f"{season}E{ep_str.zfill(2)}")

        return prefix.rstrip('._- '), tags, suffix.lstrip('._- ')

    # Pattern 2: ##x##-## (e.g. 2x01-02)
    m2 = _re.match(r'(?i)(.*?)(\d+x\d+)[-](\d+)(.*)', stem)
    if m2:
        prefix = m2.group(1).rstrip('._- ')
        first  = m2.group(2)
        second = m2.group(3)
        suffix = m2.group(4).lstrip('._- ')
        season_part = first.split('x')[0]
        ep_part     = first.split('x')[1]
        tags = [first, f"{season_part}x{second.zfill(len(ep_part))}"]
        return prefix, tags, suffix

    return None, [], None


def get_container(path: str) -> str:
    ext = Path(path).suffix.lower().lstrip(".")
    if ext == "mp4": return "mp4"
    if ext in ("mkv", "webm"): return "mkv"
    return "other"


