@dataclass
class SplitPoint:
    timestamp:   float          # cut point (seconds)
    confidence:  float          # 0.0-1.0
    duration:    float          # black segment duration (seconds)
    enabled:     bool  = True
    label:       str   = ""
    black_start: float = 0.0   # start of black segment (for keyframe snap)
    black_end:   float = 0.0   # end of black segment (for keyframe snap)
    keyframe_ts: float = -1.0  # nearest keyframe within black segment (-1 = not found yet)

@dataclass
class VideoJob:
    path:            str
    filename:        str
    status:          str  = "queued"   # queued|analyzing|ready|splitting|done|error
    split_points:    list = field(default_factory=list)
    duration:        float = 0.0
    file_size_bytes: int   = 0         # source file size for size estimation
    error:           str  = ""
    output_dir:      str  = ""
    container:       str  = "other"
    streams:         dict = field(default_factory=dict)
    n_parts_override: int  = 0         # 0 = auto-detect, 2+ = force N equal splits


# ─────────────────────────────────────────────
# FFMPEG UPDATE WORKERS
# ─────────────────────────────────────────────

class UpdateCheckWorker(QThread):
    result = pyqtSignal(object, object)
    error  = pyqtSignal(str)

    def __init__(self, manager: FFmpegManager):
        super().__init__()
        self.manager = manager

    def run(self):
        try:
            info    = self.manager.locate()
            release = self.manager.fetch_latest_release()
            self.result.emit(info, release)
        except Exception as e:
            self.error.emit(str(e))


class DownloadWorker(QThread):
    progress = pyqtSignal(str, int)
    success  = pyqtSignal(object)
    error    = pyqtSignal(str)

    def __init__(self, manager: FFmpegManager, release: ReleaseInfo):
        super().__init__()
        self.manager = manager
        self.release = release

    def run(self):
        try:
            info = self.manager.download_and_install(self.release)
            self.success.emit(info)
        except Exception as e:
            self.error.emit(str(e))


