class FFmpegUpdateDialog(QDialog):
    install_requested = pyqtSignal(object)

    def __init__(self, manager: FFmpegManager, parent=None):
        super().__init__(parent)
        self.manager  = manager
        self.release: Optional[ReleaseInfo] = None
        self._worker: Optional[DownloadWorker] = None
        self.setWindowTitle("FFmpeg Manager")
        self.setMinimumWidth(560)
        self.setModal(True)
        self._build()
        self._start_check()

    def _build(self):
        layout = QVBoxLayout(self)
        layout.setSpacing(12)
        layout.setContentsMargins(20, 20, 20, 20)

        title = QLabel("FFMPEG MANAGER")
        title.setObjectName("dialogTitle")
        layout.addWidget(title)

        # ── Installed version ──────────────────────────────────────────────
        cur_box = QGroupBox("Installed Version")
        cur_box.setObjectName("settingsGroup")
        cl = QVBoxLayout(cur_box)
        self.cur_lbl    = QLabel("Checking...")
        self.source_lbl = QLabel("")
        self.cur_lbl.setObjectName("settingLabel")
        self.source_lbl.setObjectName("settingLabel")
        cl.addWidget(self.cur_lbl)
        cl.addWidget(self.source_lbl)
        layout.addWidget(cur_box)

        # ── Latest GitHub release ──────────────────────────────────────────
        rel_box = QGroupBox("Latest Release  (BtbN / GitHub)")
        rel_box.setObjectName("settingsGroup")
        rl = QVBoxLayout(rel_box)
        self.rel_lbl     = QLabel("Fetching release info...")
        self.update_note = QLabel("")
        self.rel_lbl.setObjectName("settingLabel")
        self.update_note.setObjectName("settingLabel")
        rl.addWidget(self.rel_lbl)
        rl.addWidget(self.update_note)

        # Retry button shown only when fetch fails
        self.retry_btn = QPushButton("Retry")
        self.retry_btn.setObjectName("smallBtn")
        self.retry_btn.hide()
        self.retry_btn.clicked.connect(self._start_check)
        rl.addWidget(self.retry_btn)
        layout.addWidget(rel_box)

        # ── Progress ───────────────────────────────────────────────────────
        self.prog_label = QLabel("")
        self.prog_label.setObjectName("settingLabel")
        layout.addWidget(self.prog_label)

        # Progress bar + percentage side by side
        prog_row = QHBoxLayout()
        self.prog_bar = QProgressBar()
        self.prog_bar.setObjectName("mainProgress")
        self.prog_bar.setFixedHeight(22)
        self.prog_bar.setTextVisible(False)
        self.prog_bar.hide()
        prog_row.addWidget(self.prog_bar)
        self.prog_pct = QLabel("")
        self.prog_pct.setObjectName("pctLabel")
        self.prog_pct.setFixedWidth(42)
        self.prog_pct.hide()
        prog_row.addWidget(self.prog_pct)
        layout.addLayout(prog_row)

        # ── Buttons ────────────────────────────────────────────────────────
        btn_row = QHBoxLayout()

        self.install_btn = QPushButton("Download & Install")
        self.install_btn.setObjectName("primaryBtn")
        self.install_btn.setEnabled(False)
        self.install_btn.clicked.connect(self._do_install)
        btn_row.addWidget(self.install_btn)

        self.force_btn = QPushButton("Force Reinstall")
        self.force_btn.setObjectName("smallBtn")
        self.force_btn.setEnabled(False)
        self.force_btn.setToolTip("Re-download and reinstall even if already up to date")
        self.force_btn.clicked.connect(self._do_force_install)
        btn_row.addWidget(self.force_btn)

        gh_btn = QPushButton("GitHub Page")
        gh_btn.setObjectName("smallBtn")
        gh_btn.setToolTip("Open BtbN FFmpeg releases on GitHub")
        gh_btn.clicked.connect(lambda: QDesktopServices.openUrl(
            QUrl("https://github.com/BtbN/FFmpeg-Builds/releases/latest")
        ))
        btn_row.addWidget(gh_btn)

        close_btn = QPushButton("Close")
        close_btn.setObjectName("smallBtnGhost")
        close_btn.clicked.connect(self.accept)
        btn_row.addWidget(close_btn)
        layout.addLayout(btn_row)

    def _start_check(self):
        """Start background check for installed version + latest GitHub release."""
        self.rel_lbl.setText("Fetching release info...")
        self.retry_btn.hide()
        self.install_btn.setEnabled(False)
        self.force_btn.setEnabled(False)
        self._check_worker = UpdateCheckWorker(self.manager)
        self._check_worker.result.connect(self._on_check_result)
        self._check_worker.error.connect(self._on_check_error)
        self._check_worker.start()

    def _on_check_error(self, msg: str):
        """GitHub fetch failed — show error and a Retry button."""
        self.rel_lbl.setText(f"Could not reach GitHub: {msg}")
        self.rel_lbl.setStyleSheet("color: #f87171;")
        self.update_note.setText("Check your internet connection, then click Retry.")
        self.update_note.setStyleSheet("color: #facc15;")
        self.retry_btn.show()
        # Still allow force-install if we somehow have a cached release
        if self.release:
            self.force_btn.setEnabled(True)

    def _on_check_result(self, info: Optional[FFmpegInfo], release: Optional[ReleaseInfo]):
        self.rel_lbl.setStyleSheet("")
        self.retry_btn.hide()

        # ── Installed version section ──────────────────────────────────────
        if info:
            self.cur_lbl.setText(f"Version: {info.version}  (built {info.build_date or 'unknown'})")
            src = f"Managed: {info.path}" if info.is_local else f"System PATH: {info.path}"
            self.source_lbl.setText(src)
        else:
            self.cur_lbl.setText("Not found in managed location or system PATH")
            # Show where it WILL be installed so user isn't confused
            from ffmpeg_manager import _get_local_bin_dir
            self.source_lbl.setText(f"Will install to: {_get_local_bin_dir()}")

        # ── Latest release section ─────────────────────────────────────────
        if release:
            self.release = release
            size_mb = release.size_bytes / (1024 * 1024)
            self.rel_lbl.setText(
                f"Tag: {release.tag}  |  Published: {release.published_at}  |  {size_mb:.0f} MB"
            )
            # Force reinstall always available once we have a release
            self.force_btn.setEnabled(True)

            update_avail = self.manager.is_update_available(release)
            if not info:
                self.update_note.setText("FFmpeg not found — click Download & Install")
                self.update_note.setStyleSheet("color: #facc15;")
                self.install_btn.setText("Download & Install")
                self.install_btn.setEnabled(True)
            elif update_avail:
                self.update_note.setText("Newer build available")
                self.update_note.setStyleSheet("color: #38bdf8;")
                self.install_btn.setText("Update FFmpeg")
                self.install_btn.setEnabled(True)
            else:
                self.update_note.setText("FFmpeg is up to date")
                self.update_note.setStyleSheet("color: #4ade80;")
                self.install_btn.setEnabled(False)
        else:
            self.rel_lbl.setText("Could not fetch release info")
            self.update_note.setText("Check your internet connection and click Retry")
            self.update_note.setStyleSheet("color: #facc15;")
            self.retry_btn.show()

    def _do_install(self):
        if not self.release:
            return
        self._run_download(self.release)

    def _do_force_install(self):
        if not self.release:
            return
        self._run_download(self.release)

    def _run_download(self, release: ReleaseInfo):
        self.install_btn.setEnabled(False)
        self.force_btn.setEnabled(False)
        self.retry_btn.hide()
        self.prog_bar.show()
        self.prog_bar.setValue(0)
        self.prog_pct.setText("0%")
        self.prog_pct.show()
        self.prog_label.setText("Starting download...")

        self._worker = DownloadWorker(self.manager, release)
        self._worker.progress.connect(self._on_dl_progress)
        self._worker.success.connect(self._on_dl_success)
        self._worker.error.connect(self._on_dl_error)
        self._worker.start()

    def _on_dl_progress(self, msg: str, pct: int):
        self.prog_label.setText(msg)
        self.prog_bar.setValue(pct)
        self.prog_bar.show()
        self.prog_pct.setText(f"{pct}%")
        self.prog_pct.show()

    def _on_dl_success(self, info: FFmpegInfo):
        self.prog_bar.setValue(100)
        self.prog_pct.setText("100%")
        self.prog_label.setText(f"Installed successfully: {info.version}")
        self.cur_lbl.setText(f"Version: {info.version}  (built {info.build_date or 'unknown'})")
        self.source_lbl.setText(f"Managed: {info.path}")
        self.update_note.setText("FFmpeg is up to date")
        self.update_note.setStyleSheet("color: #4ade80;")
        self.force_btn.setEnabled(True)
        self.install_requested.emit(info)

    def _on_dl_error(self, msg: str):
        self.prog_label.setText(f"Error: {msg}")
        self.prog_bar.hide()
        self.prog_pct.hide()
        self.install_btn.setEnabled(True)
        self.force_btn.setEnabled(True)
        self.retry_btn.show()
        QMessageBox.critical(self, "Install Failed",
            f"Could not install FFmpeg:\n\n{msg}\n\n"
            "Check your internet connection and try again.")


