# ANALYSIS WORKER
# ─────────────────────────────────────────────

class AnalysisWorker(QThread):
    progress    = pyqtSignal(str, int)
    split_found = pyqtSignal(str, list, dict, float, int)
    log_message = pyqtSignal(str)
    error       = pyqtSignal(str, str)

    def __init__(self, jobs: list, settings: dict, manager: FFmpegManager):
        super().__init__()
        self.jobs     = jobs
        self.settings = settings
        self.manager  = manager
        self._cancel  = False

    def cancel(self): self._cancel = True

    def run(self):
        import traceback as _tb
        for job in self.jobs:
            if self._cancel: break
            try:
                self.log_message.emit(f"Analyzing: {job.filename}")
                self.progress.emit(job.filename, 5)
                self.log_message.emit(f"  Probing file...")
                streams, duration, fsize = self._probe_file(job.path, job)
                job.file_size_bytes = fsize
                self.log_message.emit(f"  Probe OK: {duration:.1f}s, "
                    f"video={streams.get('video_codec','?')}, "
                    f"audio={streams.get('audio_codec','?')}")
                self.progress.emit(job.filename, 20)
                self.log_message.emit(f"  Running black frame detection...")
                splits = self._detect_black_frames(job, duration)
                self.progress.emit(job.filename, 95)
                self.split_found.emit(job.filename, splits, streams, duration, fsize)
                self.log_message.emit(
                    f"  -> {len(splits)} break(s) | "
                    f"video={streams.get('video_codec','?')} "
                    f"audio={streams.get('audio_codec','?')} | "
                    f"{job.container.upper()}"
                )
                self.progress.emit(job.filename, 100)
            except Exception as e:
                full = _tb.format_exc()
                self.error.emit(job.filename, str(e) + "\n" + full)

    def _probe_file(self, path: str, job=None):
        cmd = [
            self.manager.ffprobe_path(),
            "-v", "quiet", "-print_format", "json",
            "-show_format", "-show_streams", path
        ]
        r = _run(cmd, capture_output=True, text=True, timeout=30)
        if r.returncode != 0:
            raise RuntimeError(f"ffprobe failed: {r.stderr[:300]}")
        data     = json.loads(r.stdout)
        duration = float(data.get("format", {}).get("duration", 0))
        streams  = {}
        for s in data.get("streams", []):
            ct = s.get("codec_type", "")
            if ct == "video" and "video_codec" not in streams:
                streams["video_codec"] = s.get("codec_name", "unknown")
                streams["width"]       = s.get("width", 0)
                streams["height"]      = s.get("height", 0)
            elif ct == "audio" and "audio_codec" not in streams:
                streams["audio_codec"]    = s.get("codec_name", "unknown")
                streams["audio_channels"] = s.get("channels", 0)
            elif ct == "subtitle":
                streams.setdefault("subtitle_codecs", []).append(s.get("codec_name", ""))
        # Store file size for segment size estimation
        try:
            job_file_size = os.path.getsize(path)
        except Exception:
            job_file_size = 0

        return streams, duration, job_file_size

    def _detect_black_frames(self, job, duration: float):
        s = self.settings
        cmd = [
            self.manager.ffmpeg_path(),
            "-i", job.path,
            "-vf", (f"blackdetect=d={s['black_min_duration']}"
                    f":pix_th={s['pixel_threshold']}"
                    f":pic_th={s['picture_threshold']}"),
            "-an", "-f", "null", "-"
        ]
        r = _run(cmd, capture_output=True, text=True, timeout=600)
        splits  = []
        pattern = r"black_start:([\d.]+)\s+black_end:([\d.]+)\s+black_duration:([\d.]+)"
        for m in re.finditer(pattern, r.stderr):
            start = float(m.group(1))
            end   = float(m.group(2))
            dur   = float(m.group(3))
            mid   = (start + end) / 2.0
            conf  = 0.95 if dur >= 2.0 else 0.80 if dur >= 1.0 else 0.60
            if start < 30 or (duration > 0 and start > duration - 30):
                continue

            # Try to find a keyframe within the black segment during analysis.
            # If found, keyframe_snap mode can cut there losslessly with no overlap.
            kf = self._find_keyframe_in_segment(job.path, start, end)

            splits.append(SplitPoint(
                timestamp=mid, confidence=conf, duration=dur,
                label=f"Break at {fmt_time(mid)}",
                black_start=start, black_end=end,
                keyframe_ts=kf if kf is not None else -1.0
            ))
        return splits

    def _find_keyframe_in_segment(self, path: str, seg_start: float, seg_end: float):
        """
        Scan only the black frame window for keyframes.
        Uses -skip_frame nointra so ffprobe only decodes I-frames (very fast).
        Returns the timestamp of the first keyframe within [seg_start, seg_end],
        or None if no keyframe falls in the window.
        """
        try:
            # Add small margin to ensure we catch keyframes at boundaries
            scan_from = max(0.0, seg_start - 0.25)
            scan_to   = seg_end + 0.25

            cmd = [
                self.manager.ffprobe_path(),
                "-v", "quiet",
                "-select_streams", "v:0",
                "-skip_frame", "nointra",          # only I-frames
                "-show_frames",
                "-show_entries", "frame=pkt_pts_time",
                "-of", "csv",
                "-read_intervals", f"{scan_from}%{scan_to}",
                path
            ]
            r = _run(cmd, capture_output=True, text=True, timeout=30)

            for line in r.stdout.splitlines():
                parts = line.strip().split(",")
                if len(parts) >= 2:
                    try:
                        ts = float(parts[-1])
                        if seg_start <= ts <= seg_end:
                            return ts          # first keyframe inside the black window
                    except ValueError:
                        continue
        except Exception:
            pass
        return None


