# SPLIT WORKER  (format-aware)
# ─────────────────────────────────────────────

class SplitWorker(QThread):
    progress    = pyqtSignal(str, int, str)
    done        = pyqtSignal(str, int)
    error       = pyqtSignal(str, str)
    log_message = pyqtSignal(str)

    def __init__(self, jobs: list, settings: dict, manager: FFmpegManager):
        super().__init__()
        self.jobs          = jobs
        self.settings      = settings
        self.manager       = manager
        self._cancel       = False
        # Cut mode
        self.cut_mode      = settings.get("cut_mode", "keyframe_snap")
        self.accurate_cuts = (self.cut_mode == "accurate")
        # Output encoding
        self.out_container = settings.get("out_container", "source")
        self.video_codec   = settings.get("video_codec",   "libx264")
        self.audio_codec   = settings.get("audio_codec",   "aac")
        self.preset        = settings.get("preset",        "fast")
        self.lossless      = settings.get("lossless",      False)
        self.use_crf       = settings.get("use_crf",       True)
        self.crf           = settings.get("crf",           18)
        self.bitrate_kbps  = settings.get("bitrate_kbps",  0)

    def cancel(self): self._cancel = True

    def run(self):
        # NOTE: we do NOT check job.status here — the caller is responsible
        # for passing only the jobs that should be split. Checking status
        # here caused the "0 files split" bug because status had already
        # been changed to "splitting" before this worker started.
        for job in self.jobs:
            if self._cancel: break
            try:
                self._split_file(job)
            except Exception as e:
                self.error.emit(job.filename, str(e))

    def _split_file(self, job: VideoJob):
        enabled = sorted([sp for sp in job.split_points if sp.enabled], key=lambda x: x.timestamp)
        out_dir = job.output_dir or str(Path(job.path).parent / "episodes")
        os.makedirs(out_dir, exist_ok=True)

        stem    = Path(job.path).stem
        src_ext = Path(job.path).suffix.lower()
        ext_map = {"mp4": ".mp4", "mkv": ".mkv", "source": src_ext}
        ext     = ext_map.get(self.out_container, src_ext)

        # ── Naming: TMDB/TVDB plan > filename pattern > generic ──────────────
        naming_plan = getattr(self, '_naming_plan', None)
        use_plan_names = (naming_plan and naming_plan.confirmed
                          and len(naming_plan.output_names) >= num_segs)

        ep_prefix, ep_tags, ep_suffix = detect_episode_range(job.filename)
        use_ep_names = (not use_plan_names and ep_tags
                        and len(ep_tags) == len(enabled) + 1)
        if use_plan_names:
            self.log_message.emit(f"  Using TMDB/TVDB names for {job.filename}")
        elif use_ep_names:
            self.log_message.emit(
                f"  Smart naming: detected {ep_tags} — outputs will use episode tags"
            )

        # Build boundary timestamps.
        # In keyframe_snap mode, use the pre-found keyframe timestamp for each
        # split point so that every cut lands on an exact keyframe — no overlap,
        # no re-encode, no quality loss.
        def effective_ts(sp):
            if self.cut_mode == "keyframe_snap" and sp.keyframe_ts >= 0:
                return sp.keyframe_ts   # exact keyframe inside the black segment
            return sp.timestamp         # midpoint fallback

        boundaries = [0.0] + [effective_ts(sp) for sp in enabled] + [job.duration]
        num_segs   = len(boundaries) - 1

        mode_label = {
            "keyframe_snap": "keyframe snap (lossless)",
            "accurate":      "accurate re-encode",
            "smart":         "smart encode (re-encode start only)",
            "stream_copy":   "stream copy",
        }.get(self.cut_mode, self.cut_mode)

        self.log_message.emit(
            f"Splitting {job.filename} into {num_segs} segment(s) "
            f"[{mode_label}] -> {out_dir}"
        )

        for i, (t_start, t_end) in enumerate(zip(boundaries[:-1], boundaries[1:])):
            if self._cancel: return
            ep_num   = i + 1
            duration = t_end - t_start
            if use_plan_names:
                out_name = naming_plan.output_names[i]
            elif use_ep_names:
                tag = ep_tags[i]
                base = ep_prefix + ("." if ep_prefix else "")
                suf  = ("." + ep_suffix) if ep_suffix else ""
                out_name = f"{base}{tag}{suf}{ext}"
            else:
                out_name = f"{stem}_{ep_num:03d}{ext}"
            out_path = os.path.join(out_dir, out_name)

            self.progress.emit(job.filename, int((i / num_segs) * 90),
                               f"Writing episode {ep_num}/{num_segs}...")
            self.log_message.emit(f"  -> {out_name}  [{fmt_time(t_start)} -> {fmt_time(t_end)}]")

            if self.cut_mode == "smart" and i > 0:
                # Smart encode: re-encode only the opening seconds of each
                # part that starts at a cut point, stream copy everything else.
                # Part 1 (i=0) always starts at 0 and needs no re-encode.
                success = self._smart_split_segment(job, t_start, t_end, out_path)
                if not success:
                    self.log_message.emit(f"  ! Smart encode failed, falling back to full re-encode...")
                    cmd = self._build_cmd(job, t_start, duration, out_path, force_encode=True)
                    r   = _run(cmd, capture_output=True, text=True, timeout=7200)
                    if r.returncode != 0:
                        raise RuntimeError(f"FFmpeg failed ep {ep_num}:\n{r.stderr[-400:]}")
            else:
                cmd = self._build_cmd(job, t_start, duration, out_path)
                r   = _run(cmd, capture_output=True, text=True, timeout=7200)
                if r.returncode != 0:
                    self.log_message.emit(f"  ! Copy failed, retrying with re-encode...")
                    cmd2 = self._build_cmd(job, t_start, duration, out_path, force_encode=True)
                    r2   = _run(cmd2, capture_output=True, text=True, timeout=7200)
                    if r2.returncode != 0:
                        raise RuntimeError(f"FFmpeg failed ep {ep_num}:\n{r2.stderr[-400:]}")

        self.progress.emit(job.filename, 100, "Done")
        self.done.emit(job.filename, num_segs)

    def _find_next_keyframe_after(self, path: str, ts: float) -> Optional[float]:
        """Find the first keyframe timestamp strictly after ts."""
        try:
            cmd = [
                self.manager.ffprobe_path(),
                "-v", "quiet",
                "-select_streams", "v:0",
                "-skip_frame", "nointra",
                "-show_frames",
                "-show_entries", "frame=pkt_pts_time",
                "-of", "csv",
                "-read_intervals", f"{ts}%{ts + 30}",  # scan 30s window
                path
            ]
            r = _run(cmd, capture_output=True, text=True, timeout=30)
            for line in r.stdout.splitlines():
                parts = line.strip().split(",")
                if len(parts) >= 2:
                    try:
                        kf = float(parts[-1])
                        if kf > ts + 0.01:   # strictly after
                            return kf
                    except ValueError:
                        continue
        except Exception:
            pass
        return None

    def _smart_split_segment(self, job: VideoJob, t_start: float, t_end: float,
                             out_path: str) -> bool:
        """
        Smart encode: re-encode only the opening frames of a segment so the
        cut is frame-exact, then stream copy the rest. Much faster than a
        full re-encode — typically only 3-10 seconds of video is re-encoded
        regardless of total episode length.

        Steps:
          1. Find the first keyframe AFTER t_start  (KF_after)
          2. Re-encode  [t_start ... KF_after]  -> tmp_intro  (few seconds)
          3. Stream copy [KF_after ... t_end]   -> tmp_rest
          4. FFmpeg concat tmp_intro + tmp_rest -> out_path
          5. Clean up temp files
        """
        ffmpeg    = self.manager.ffmpeg_path()
        kf_after  = self._find_next_keyframe_after(job.path, t_start)

        if kf_after is None or kf_after >= t_end:
            # No keyframe found in reasonable range — fall back to full re-encode
            return False

        intro_dur = kf_after - t_start
        rest_dur  = t_end - kf_after
        tmp_dir   = tempfile.mkdtemp(prefix="episplit_")
        out_ext   = Path(out_path).suffix.lower()
        intro_path = os.path.join(tmp_dir, f"intro{out_ext}")
        rest_path  = os.path.join(tmp_dir, f"rest{out_ext}")
        concat_txt = os.path.join(tmp_dir, "concat.txt")

        try:
            # ── Step 1: Re-encode the intro (t_start → KF_after) ──────────
            # Use -ss AFTER -i for frame-accurate start
            cmd_intro = [
                ffmpeg, "-y",
                "-i", job.path,
                "-ss", f"{t_start:.6f}",
                "-t",  f"{intro_dur:.6f}",
                "-c:v", "libx264", "-crf", str(self.crf), "-preset", self.preset,
                "-c:a", "aac", "-b:a", "192k",
                "-map", "0:v:0", "-map", "0:a:0",
                intro_path
            ]
            r1 = _run(cmd_intro, capture_output=True, text=True, timeout=300)
            if r1.returncode != 0:
                return False

            self.log_message.emit(
                f"     Smart encode: {intro_dur:.1f}s intro re-encoded, "
                f"{rest_dur:.1f}s stream copied"
            )

            # ── Step 2: Stream copy the rest (KF_after → t_end) ───────────
            cmd_rest = [
                ffmpeg, "-y",
                "-ss", f"{kf_after:.6f}",
                "-i", job.path,
                "-t",  f"{rest_dur:.6f}",
                "-c", "copy", "-map", "0",
                "-avoid_negative_ts", "make_zero",
                rest_path
            ]
            r2 = _run(cmd_rest, capture_output=True, text=True, timeout=7200)
            if r2.returncode != 0:
                return False

            # ── Step 3: Concat intro + rest ────────────────────────────────
            # Write concat list with safely-quoted paths
            with open(concat_txt, "w", encoding="utf-8") as cf:
                cf.write("file " + repr(intro_path) + "\n")
                cf.write("file " + repr(rest_path) + "\n")

            cmd_cat = [
                ffmpeg, "-y",
                "-f", "concat", "-safe", "0",
                "-i", concat_txt,
                "-c", "copy",
                out_path
            ]
            r3 = _run(cmd_cat, capture_output=True, text=True, timeout=7200)
            return r3.returncode == 0

        except Exception as e:
            self.log_message.emit(f"     Smart encode error: {e}")
            return False
        finally:
            shutil.rmtree(tmp_dir, ignore_errors=True)

    def _build_cmd(self, job: VideoJob, t_start: float, duration: float,
                   out_path: str, force_encode: bool = False) -> list:
        """
        Build the FFmpeg command based on cut mode and output encoding settings.

        Keyframe snap / Stream copy:
          Uses -c copy — fast, lossless, no quality change.
          Container can still be changed (e.g. MKV -> MP4).

        Accurate re-encode / force_encode fallback:
          Full re-encode using the chosen codec, preset, and quality settings.
          Supports H.264, H.265/HEVC, AV1, with CRF or bitrate targeting.
          Lossless mode uses codec-specific lossless flags.
        """
        ffmpeg        = self.manager.ffmpeg_path()
        accurate      = self.accurate_cuts or force_encode
        container     = self.out_container   # "source" | "mp4" | "mkv"
        # Resolve actual output container from extension
        out_ext = Path(out_path).suffix.lower().lstrip(".")
        is_mp4  = out_ext == "mp4"
        is_mkv  = out_ext in ("mkv", "webm")
        subs    = job.streams.get("subtitle_codecs", [])
        safe_mp4_subs = {"mov_text", "tx3g"}

        if accurate:
            # ── Re-encode mode ────────────────────────────────────────────
            # -ss AFTER -i for frame-accurate decode
            base = [
                ffmpeg, "-y",
                "-i",  job.path,
                "-ss", f"{t_start:.6f}",
                "-t",  f"{duration:.6f}",
            ]

            # ── Video codec flags ─────────────────────────────────────────
            vcodec   = self.video_codec   # copy|libx264|libx265|hevc_nvenc|libsvtav1
            is_nvenc  = vcodec == "hevc_nvenc"
            is_copy   = vcodec == "copy"

            if is_copy:
                # Stream-copy video — fastest, lossless, keeps original codec
                v_flags = ["-c:v", "copy"]
            elif self.lossless:
                if vcodec == "libx264":
                    v_flags = ["-c:v", "libx264", "-qp", "0", "-preset", self.preset]
                elif vcodec == "libx265":
                    v_flags = ["-c:v", "libx265", "-x265-params", "lossless=1", "-preset", self.preset]
                elif is_nvenc:
                    v_flags = ["-c:v", "hevc_nvenc", "-qp", "0", "-preset", "lossless"]
                elif vcodec == "libsvtav1":
                    v_flags = ["-c:v", "libsvtav1", "-qp", "0", "-preset", self.preset]
                else:
                    v_flags = ["-c:v", vcodec, "-qp", "0"]
            elif is_nvenc:
                # NVENC uses -qp (not -crf) and its own preset names
                nvenc_preset_map = {
                    "ultrafast": "p1", "superfast": "p1", "veryfast": "p2",
                    "faster": "p3", "fast": "p4", "medium": "p5",
                    "slow": "p6", "veryslow": "p7",
                }
                nvp = nvenc_preset_map.get(self.preset, "p4")
                if self.use_crf:
                    v_flags = ["-c:v", "hevc_nvenc", "-qp", str(self.crf), "-preset", nvp]
                else:
                    br = f"{self.bitrate_kbps}k" if self.bitrate_kbps > 0 else "4000k"
                    v_flags = ["-c:v", "hevc_nvenc", "-b:v", br, "-preset", nvp]
            elif self.use_crf:
                v_flags = ["-c:v", vcodec, "-crf", str(self.crf), "-preset", self.preset]
            else:
                br = f"{self.bitrate_kbps}k" if self.bitrate_kbps > 0 else "4000k"
                if vcodec == "libsvtav1":
                    v_flags = ["-c:v", vcodec, "-b:v", br, "-preset", self.preset]
                else:
                    v_flags = [
                        "-c:v", vcodec, "-b:v", br,
                        "-maxrate", str(int(self.bitrate_kbps * 1.5)) + "k",
                        "-bufsize", str(int(self.bitrate_kbps * 2)) + "k",
                        "-preset", self.preset,
                    ]

            # ── Audio codec flags ─────────────────────────────────────────
            acodec = self.audio_codec   # aac | ac3 | copy
            if acodec == "copy":
                a_flags = ["-c:a", "copy"]
            elif acodec == "ac3":
                a_flags = ["-c:a", "ac3", "-b:a", "448k"]
            else:
                a_flags = ["-c:a", "aac", "-b:a", "192k"]

            # ── Stream mapping & container flags ──────────────────────────
            if is_mp4:
                sub_flags = (["-map", "0:s", "-c:s", "mov_text"]
                             if any(c in safe_mp4_subs for c in subs) else [])
                stream_maps = ["-map", "0:v:0", "-map", "0:a:0"] + sub_flags
                out_flags   = ["-movflags", "+faststart"]
            elif is_mkv:
                stream_maps = ["-map", "0:v:0", "-map", "0:a:0",
                               "-map", "0:s?", "-c:s", "copy"]
                out_flags   = []
            else:
                stream_maps = ["-map", "0:v:0", "-map", "0:a:0"]
                out_flags   = []

            return base + v_flags + a_flags + stream_maps + out_flags + [out_path]

        else:
            # ── Stream copy mode ──────────────────────────────────────────
            # -ss BEFORE -i: fast keyframe seek
            base = [
                ffmpeg, "-y",
                "-ss", f"{t_start:.6f}",
                "-i",  job.path,
                "-t",  f"{duration:.6f}",
            ]
            if is_mp4:
                codec_flags = ["-c:v", "copy", "-c:a", "copy",
                               "-map", "0:v", "-map", "0:a"]
                if any(c in safe_mp4_subs for c in subs):
                    codec_flags += ["-map", "0:s", "-c:s", "mov_text"]
                out_flags = ["-movflags", "+faststart", "-avoid_negative_ts", "make_zero"]
            elif is_mkv:
                codec_flags = ["-c", "copy", "-map", "0"]
                out_flags   = ["-avoid_negative_ts", "make_zero"]
            else:
                codec_flags = ["-c", "copy", "-map", "0"]
                out_flags   = ["-avoid_negative_ts", "make_zero"]

            return base + codec_flags + out_flags + [out_path]


