class SplitPointRow(QFrame):
    toggled = pyqtSignal()
    deleted = pyqtSignal(object)

    def __init__(self, sp: SplitPoint, seg_label: str, size_est: str, parent=None):
        super().__init__(parent)
        self.sp = sp
        self.seg_label = seg_label
        self.size_est  = size_est
        self._build()

    def _build(self):
        self.setObjectName("splitRow")
        layout = QHBoxLayout(self)
        layout.setContentsMargins(12, 6, 12, 6)
        layout.setSpacing(10)

        check = QCheckBox()
        check.setChecked(self.sp.enabled)
        check.toggled.connect(lambda c: (setattr(self.sp, "enabled", c), self.toggled.emit()))
        layout.addWidget(check)

        # Segment label e.g. "Cut 1"
        seg_lbl = QLabel(self.seg_label)
        seg_lbl.setObjectName("splitSegLabel")
        seg_lbl.setMinimumWidth(38)
        layout.addWidget(seg_lbl)

        time_lbl = QLabel(fmt_time(self.sp.timestamp))
        time_lbl.setObjectName("splitTime")
        time_lbl.setMinimumWidth(90)
        layout.addWidget(time_lbl)

        dur_lbl = QLabel(f"{self.sp.duration:.2f}s black")
        dur_lbl.setObjectName("splitDetail")
        layout.addWidget(dur_lbl)

        conf_pct = int(self.sp.confidence * 100)
        color    = "#4ade80" if conf_pct >= 80 else "#facc15" if conf_pct >= 60 else "#f87171"
        conf_lbl = QLabel(f"{conf_pct}%")
        conf_lbl.setStyleSheet(f"color: {color}; font-size: 11px;")
        conf_lbl.setMinimumWidth(28)
        layout.addWidget(conf_lbl)

        # Keyframe snap indicator
        if self.sp.keyframe_ts >= 0:
            kf_lbl = QLabel("KF")
            kf_lbl.setObjectName("kfLabel")
            kf_lbl.setToolTip(f"Keyframe found at {fmt_time(self.sp.keyframe_ts)} — lossless snap available")
            layout.addWidget(kf_lbl)

        layout.addStretch()

        # Estimated output size
        size_lbl = QLabel(self.size_est)
        size_lbl.setObjectName("sizeEstLabel")
        layout.addWidget(size_lbl)

        del_btn = QPushButton("X")
        del_btn.setObjectName("deleteBtn")
        del_btn.setFixedSize(24, 24)
        del_btn.clicked.connect(lambda: self.deleted.emit(self.sp))
        layout.addWidget(del_btn)


class SplitEditor(QWidget):
    changed      = pyqtSignal()
    apply_n_parts = pyqtSignal(int)   # user clicked "Apply N equal parts"

    def __init__(self, parent=None):
        super().__init__(parent)
        self.job:      Optional[VideoJob] = None
        self._rows:    list               = []
        self._cut_mode = "keyframe_snap"   # kept in sync by MainWindow
        self._crf      = 18
        self._build()

    def _build(self):
        layout = QVBoxLayout(self)
        layout.setContentsMargins(0, 0, 0, 0)
        layout.setSpacing(0)

        # ── Header row ────────────────────────────────────────────────────
        hdr_frame = QFrame(); hdr_frame.setObjectName("sectionHeaderFrame")
        hdr_row   = QHBoxLayout(hdr_frame)
        hdr_row.setContentsMargins(16, 6, 12, 6)
        hdr_lbl = QLabel("SPLIT POINTS"); hdr_lbl.setObjectName("sectionHeader")
        hdr_row.addWidget(hdr_lbl)
        hdr_row.addStretch()

        # "Split into N equal parts" inline control
        n_lbl = QLabel("Equal parts:"); n_lbl.setObjectName("settingLabel")
        hdr_row.addWidget(n_lbl)
        self.n_parts_spin = QSpinBox()
        self.n_parts_spin.setRange(0, 99); self.n_parts_spin.setValue(0)
        self.n_parts_spin.setSpecialValueText("auto")   # 0 = use detected splits
        self.n_parts_spin.setFixedWidth(58)
        self.n_parts_spin.setObjectName("spinBox")
        self.n_parts_spin.setToolTip(
            "0 = auto-detected splits. 2+ = N evenly-spaced splits."
        )
        hdr_row.addWidget(self.n_parts_spin)
        apply_btn = QPushButton("Apply")
        apply_btn.setObjectName("smallBtn")
        apply_btn.setFixedWidth(50)
        apply_btn.clicked.connect(self._apply_n_parts)
        hdr_row.addWidget(apply_btn)
        layout.addWidget(hdr_frame)

        self.empty_lbl = QLabel("Select a file to view its detected split points")
        self.empty_lbl.setObjectName("emptyLabel")
        self.empty_lbl.setAlignment(Qt.AlignmentFlag.AlignCenter)
        layout.addWidget(self.empty_lbl)

        self.scroll = QScrollArea()
        self.scroll.setWidgetResizable(True)
        self.scroll.setObjectName("splitScroll")
        self.scroll.hide()
        self.inner = QWidget()
        self.il    = QVBoxLayout(self.inner)
        self.il.setContentsMargins(0, 0, 0, 0)
        self.il.setSpacing(2)
        self.il.addStretch()
        self.scroll.setWidget(self.inner)
        layout.addWidget(self.scroll)

        # ── Size summary bar ──────────────────────────────────────────────
        self.size_bar = QLabel("")
        self.size_bar.setObjectName("sizeBar")
        self.size_bar.hide()
        layout.addWidget(self.size_bar)

        self.stream_bar = QLabel("")
        self.stream_bar.setObjectName("streamBar")
        self.stream_bar.hide()
        layout.addWidget(self.stream_bar)

        # ── Manual add ────────────────────────────────────────────────────
        add_bar = QHBoxLayout()
        add_bar.setContentsMargins(12, 8, 12, 8)
        self.time_input = QLineEdit()
        self.time_input.setPlaceholderText("MM:SS  or  HH:MM:SS  or  seconds")
        self.time_input.setObjectName("timeInput")
        add_bar.addWidget(self.time_input)
        add_btn = QPushButton("+ Add Split")
        add_btn.setObjectName("addSplitBtn")
        add_btn.clicked.connect(self._add_manual)
        add_bar.addWidget(add_btn)
        layout.addLayout(add_bar)

    def load_job(self, job: Optional[VideoJob]):
        self.job = job
        self._refresh()

    def _refresh(self):
        if not self.job:
            self.empty_lbl.show(); self.scroll.hide()
            self.stream_bar.hide(); self.size_bar.hide()
            return

        self.empty_lbl.hide(); self.scroll.show()

        for row in self._rows: row.setParent(None)
        self._rows.clear()

        for i in reversed(range(self.il.count())):
            item = self.il.itemAt(i)
            if item and item.spacerItem():
                self.il.removeItem(item)

        # Build boundaries for size estimation
        enabled     = sorted([sp for sp in self.job.split_points if sp.enabled],
                             key=lambda x: x.timestamp)
        boundaries  = [0.0] + [sp.timestamp for sp in enabled] + [self.job.duration]
        seg_durations = [boundaries[i+1] - boundaries[i] for i in range(len(boundaries)-1)]

        if not self.job.split_points:
            no_lbl = QLabel("  No splits detected — whole file will be output as one segment")
            no_lbl.setObjectName("splitDetail")
            no_lbl.setStyleSheet("color: #facc15; padding: 12px;")
            self.il.addWidget(no_lbl)
            self._rows.append(no_lbl)
        else:
            # Size of segment 1 (before first cut)
            first_size = estimate_segment_size(
                self.job, seg_durations[0], self._cut_mode, self._crf
            ) if seg_durations else "?"

            # Add a row for the implicit first segment
            first_lbl = QLabel(
                f"  Part 001  [{fmt_time(0.0)} -> {fmt_time(boundaries[1] if len(boundaries)>1 else self.job.duration)}]"
                f"  ~{first_size}"
            )
            first_lbl.setObjectName("segSummaryLabel")
            self.il.addWidget(first_lbl)
            self._rows.append(first_lbl)

            # One row per cut (which starts a new segment)
            for idx, sp in enumerate(sorted(self.job.split_points, key=lambda x: x.timestamp)):
                seg_idx   = idx + 1            # which output segment this cut starts
                seg_dur   = seg_durations[seg_idx] if seg_idx < len(seg_durations) else 0
                size_est  = estimate_segment_size(self.job, seg_dur, self._cut_mode, self._crf)
                seg_label = f"{seg_idx+1:03d}"

                row = SplitPointRow(sp, seg_label, f"~{size_est}")
                row.toggled.connect(self.changed.emit)
                row.deleted.connect(self._delete_sp)
                self.il.addWidget(row)
                self._rows.append(row)

        self.il.addStretch()

        # ── Size summary ──────────────────────────────────────────────────
        n_segs = len(enabled) + 1
        if self.job.duration > 0 and self.job.file_size_bytes > 0:
            total_est = estimate_segment_size(
                self.job, self.job.duration, self._cut_mode, self._crf
            )
            src_size = fmt_size(self.job.file_size_bytes)
            avg_dur  = self.job.duration / n_segs
            avg_size = estimate_segment_size(self.job, avg_dur, self._cut_mode, self._crf)
            self.size_bar.setText(
                f"  Source: {src_size}  |  "
                f"{n_segs} part{'s' if n_segs!=1 else ''}  |  "
                f"avg ~{avg_size} each  |  "
                f"total out ~{total_est}"
            )
            self.size_bar.show()
        else:
            self.size_bar.hide()

        # ── Stream info ───────────────────────────────────────────────────
        s = self.job.streams
        if s:
            parts = []
            if "video_codec" in s:
                parts.append(f"Video: {s['video_codec'].upper()} {s.get('width','?')}x{s.get('height','?')}")
            if "audio_codec" in s:
                parts.append(f"Audio: {s['audio_codec'].upper()} {s.get('audio_channels','?')}ch")
            subs = s.get("subtitle_codecs", [])
            if subs:
                parts.append(f"Subs: {', '.join(subs)}")
            note = {"mp4": "MP4 - incompatible subs auto-dropped",
                    "mkv": "MKV - all streams preserved"}.get(
                        self.job.container, self.job.container.upper())
            self.stream_bar.setText("  " + "  |  ".join(parts) + f"  |  {note}")
            self.stream_bar.show()
        else:
            self.stream_bar.hide()

    def _delete_sp(self, sp: SplitPoint):
        if self.job and sp in self.job.split_points:
            self.job.split_points.remove(sp)
            self._refresh(); self.changed.emit()

    def set_cut_mode(self, mode: str, crf: int):
        """Called by MainWindow whenever cut mode or CRF changes so sizes stay live."""
        self._cut_mode = mode
        self._crf      = crf
        self._refresh()

    def _apply_n_parts(self):
        """Replace split points with N-1 evenly spaced cuts."""
        if not self.job: return
        n = self.n_parts_spin.value()
        if n < 2:
            # 0 or 1 = revert to detected (clear manual evens)
            self._refresh(); return
        dur = self.job.duration
        if dur <= 0: return
        step = dur / n
        self.job.split_points = [
            SplitPoint(
                timestamp=step * i,
                confidence=1.0,
                duration=0.0,
                label=f"Even split {i}/{n-1}"
            )
            for i in range(1, n)
        ]
        self._refresh(); self.changed.emit()

    def _add_manual(self):
        if not self.job: return
        raw = self.time_input.text().strip()
        try:
            if ":" in raw:
                parts = raw.replace(",", ".").split(":")
                ts = (int(parts[0])*3600 + int(parts[1])*60 + float(parts[2])
                      if len(parts) == 3 else int(parts[0])*60 + float(parts[1]))
            else:
                ts = float(raw)
        except Exception:
            return
        self.job.split_points.append(SplitPoint(
            timestamp=ts, confidence=1.0, duration=0.0, label=f"Manual at {fmt_time(ts)}"
        ))
        self.time_input.clear()
        self._refresh(); self.changed.emit()


# ─────────────────────────────────────────────
# DRAG-DROP FILE LIST
# ─────────────────────────────────────────────

class FileListWidget(QListWidget):
    files_dropped = pyqtSignal(list)

    def __init__(self, parent=None):
        super().__init__(parent)
        self.setAcceptDrops(True)
        self.setDragDropMode(QAbstractItemView.DragDropMode.DropOnly)
        self.setSelectionMode(QAbstractItemView.SelectionMode.SingleSelection)

    def dragEnterEvent(self, e: QDragEnterEvent):
        if e.mimeData().hasUrls(): e.acceptProposedAction()

    def dragMoveEvent(self, e):
        if e.mimeData().hasUrls(): e.acceptProposedAction()

    def dropEvent(self, e: QDropEvent):
        paths = []
        for url in e.mimeData().urls():
            p = url.toLocalFile()
            if p.lower().endswith(VIDEO_EXTENSIONS):
                paths.append(p)
            elif os.path.isdir(p):
                for f in Path(p).rglob("*"):
                    if f.suffix.lower() in VIDEO_EXTENSIONS:
                        paths.append(str(f))
        if paths: self.files_dropped.emit(paths)


# ─────────────────────────────────────────────
# STABLE SPLITTER  (prevents snap-back)
# ─────────────────────────────────────────────

class StableSplitter(QSplitter):
    """
    QSplitter that keeps handles where the user put them.

    Qt's QSplitter calls doResize() whenever it receives a LayoutRequest
    event from a child — this happens whenever any widget inside a panel
    changes its sizeHint (showing/hiding labels, loading content, etc.).
    doResize() re-distributes space and moves handles back.

    Fix: a 50 ms repeating timer that checks whether sizes drifted from the
    last user-set position and, if so, restores them.  Crucially, _enforce()
    never updates self._locked — only user drags and explicit setSizes() calls
    do.  This means a content-triggered redistribution can never permanently
    corrupt the locked position.

    Drag tracking prevents the timer from fighting an active drag.
    resizeEvent handles window resizing by scaling _locked proportionally.
    """

    def __init__(self, orientation=Qt.Orientation.Horizontal, parent=None):
        super().__init__(orientation, parent)
        self._locked: list = []
        self._dragging: bool = False
        self._timer = QTimer(self)
        self._timer.setInterval(50)
        self._timer.timeout.connect(self._enforce)
        self.splitterMoved.connect(self._on_user_moved)

    # ── Called only on genuine user drags ────────────────────────────────────
    def _on_user_moved(self, pos: int = 0, idx: int = 0):
        actual = self.sizes()
        if actual and sum(actual) > 0:
            self._locked = list(actual)

    # ── Called by MainWindow to set initial positions ─────────────────────────
    def setSizes(self, sizes: list):
        super().setSizes(sizes)
        actual = self.sizes()
        if actual and sum(actual) > 0:
            self._locked = list(actual)
            if not self._timer.isActive():
                self._timer.start()

    # ── Fired every 50 ms ─────────────────────────────────────────────────────
    def _enforce(self):
        if not self._locked or self._dragging:
            return
        current = self.sizes()
        if not current or current == self._locked:
            return
        # Ignore genuine window resizes (total changes by > 20 px).
        # Content-triggered snaps keep the total identical — only the
        # distribution changes.
        if abs(sum(current) - sum(self._locked)) > 20:
            return
        # Restore. blockSignals prevents splitterMoved from firing, which
        # would call _on_user_moved and corrupt _locked with the wrong values.
        self.blockSignals(True)
        super().setSizes(self._locked)
        self.blockSignals(False)
        # NOTE: do NOT update self._locked here — that is intentional.
        # Only user drags and setSizes() update the lock.

    # ── Track drag start / end so the timer doesn't fight active drags ────────
    def mousePressEvent(self, event):
        self._dragging = True
        super().mousePressEvent(event)

    def mouseReleaseEvent(self, event):
        super().mouseReleaseEvent(event)
        self._dragging = False
        # Record wherever the user let go
        actual = self.sizes()
        if actual and sum(actual) > 0:
            self._locked = list(actual)

    # ── Window resize: scale locked positions proportionally ──────────────────
    def resizeEvent(self, event):
        if not self._locked:
            super().resizeEvent(event)
            return
        old_total = sum(self._locked)
        super().resizeEvent(event)
        if old_total <= 0:
            return
        new_total = sum(self.sizes())
        if new_total > 0 and abs(new_total - old_total) > 20:
            factor = new_total / old_total
            scaled = [max(20, round(s * factor)) for s in self._locked]
            diff = new_total - sum(scaled)
            scaled[-1] = max(20, scaled[-1] + diff)
            self._locked = scaled
            self.blockSignals(True)
            super().setSizes(scaled)
            self.blockSignals(False)
