class MainWindow(QMainWindow):
    def __init__(self):
        super().__init__()
        self.jobs:             dict[str, VideoJob]      = {}
        self.analysis_worker:  Optional[AnalysisWorker] = None
        self.split_worker:     Optional[SplitWorker]    = None
        self.output_dir   = ""
        self.manager      = FFmpegManager()
        self._batch_mode  = False   # True = auto-split after analysis finishes
        self._naming_plans: dict = {}    # filename -> NamingPlan
        self._tmdb_api_key: str  = ""
        self._tvdb_api_key: str  = ""

        self.setWindowTitle("SplitRename v1.6.0 by apennismightier")
        self.setMinimumSize(1200, 750)
        self.resize(1550, 860)
        self._apply_styles()
        self._build_ui()
        # Apply sizes after window is fully rendered (retry until geometry is real)
        QTimer.singleShot(150, self._apply_splitter_sizes)
        QTimer.singleShot(400, self._startup_check)

    # ── BUILD UI ─────────────────────────────

    def _build_ui(self):
        central = QWidget()
        self.setCentralWidget(central)
        root = QVBoxLayout(central)
        root.setContentsMargins(0, 0, 0, 0)
        root.setSpacing(0)

        root.addWidget(self._build_header())

        # ── Main body (everything except header/statusbar/log) ────────────
        body = QWidget()
        body_lay = QVBoxLayout(body)
        body_lay.setContentsMargins(0, 0, 0, 0)
        body_lay.setSpacing(0)

        # Top row: file list (left) | split points (right), fixed height
        top_row = QWidget()
        top_row.setFixedHeight(220)
        tr_lay = QHBoxLayout(top_row)
        tr_lay.setContentsMargins(0, 0, 0, 0)
        tr_lay.setSpacing(0)
        tr_lay.addWidget(self._build_file_list_panel(), stretch=1)
        tr_lay.addWidget(self._build_right_panel(), stretch=1)
        body_lay.addWidget(top_row)

        # Divider
        div = QFrame(); div.setFrameShape(QFrame.Shape.HLine)
        div.setObjectName("divider")
        body_lay.addWidget(div)

        # Settings row: 3 columns spread across full width
        body_lay.addWidget(self._build_settings(), stretch=1)

        # Compact action bar
        body_lay.addWidget(self._build_action_bar())

        # ── Outer splitter: body | log ────────────────────────────────────
        self.outer_splitter = StableSplitter(Qt.Orientation.Vertical)
        self.outer_splitter.setObjectName("outerSplitter")
        self.outer_splitter.setChildrenCollapsible(False)
        self.outer_splitter.addWidget(body)
        self.outer_splitter.addWidget(self._build_log_bar())

        root.addWidget(self.outer_splitter, stretch=1)
        root.addWidget(self._build_status_bar())

