    # ── STARTUP ──────────────────────────────

    def _apply_splitter_sizes(self):
        """Set outer splitter (body | log). Log gets ~110px, body gets the rest."""
        h = self.outer_splitter.height()
        if h < 200:
            QTimer.singleShot(50, self._apply_splitter_sizes)
            return
        log_h  = 110
        body_h = max(200, h - log_h)
        self.outer_splitter.setSizes([body_h, log_h])

    def _restore_splitter_sizes(self):
        pass



    def _startup_check(self):
        info = self.manager.locate()
        self._update_ffmpeg_label(info)

    def _update_ffmpeg_label(self, info: Optional[FFmpegInfo]):
        if info:
            src = "managed" if info.is_local else "system"
            self.ffmpeg_status.setText(f"FFmpeg {info.version} ({src})")
            self.ffmpeg_status.setStyleSheet("color: #4ade80; font-size: 11px;")
        else:
            self.ffmpeg_status.setText("FFmpeg not found — open FFmpeg Manager")
            self.ffmpeg_status.setStyleSheet("color: #f87171; font-size: 11px;")

    def _open_ffmpeg_manager(self):
        dlg = FFmpegUpdateDialog(self.manager, self)
        dlg.install_requested.connect(self._update_ffmpeg_label)
        dlg.exec()
        self._update_ffmpeg_label(self.manager.locate())

    # ── FILES ─────────────────────────────────

    def _add_files(self):
        paths, _ = QFileDialog.getOpenFileNames(
            self, "Select Video Files", "",
            "Video Files (*.mp4 *.mkv *.avi *.mov *.ts *.m2ts *.wmv);;All Files (*)"
        )
        if paths: self._add_paths(paths)

    def _add_folder(self):
        folder = QFileDialog.getExistingDirectory(self, "Select Folder Containing Videos")
        if folder:
            paths = []
            for f in Path(folder).rglob("*"):
                if f.suffix.lower() in VIDEO_EXTENSIONS:
                    paths.append(str(f))
            if paths:
                self._add_paths(paths)
                self._log(f"Added {len(paths)} file(s) from folder: {folder}")
            else:
                QMessageBox.information(self, "No Videos Found",
                    f"No supported video files found in:\n{folder}")

    def _add_paths(self, paths: list):
        added = 0
        for path in paths:
            filename = os.path.basename(path)
            if filename in self.jobs: continue
            self.jobs[filename] = VideoJob(
                path=path, filename=filename, container=get_container(path)
            )
            item = QListWidgetItem(f"  {filename}")
            item.setData(Qt.ItemDataRole.UserRole, filename)
            item.setForeground(QColor("#94a3b8"))
            self.file_list.addItem(item)
            added += 1
        if added:
            self._update_file_count()

    def _clear_files(self):
        self.jobs.clear(); self.file_list.clear()
        self.split_editor.load_job(None)
        self.file_title.setText("NO FILE SELECTED"); self.ep_count_label.setText("")
        self.split_btn.setEnabled(False); self._update_file_count()

    def _select_all_files(self):
        self.file_list.selectAll()

    def _apply_settings_to_selected(self):
        """
        Stamp the current split-count setting onto every selected file.

        Works on ALL files regardless of status:
          - Queued files: stores n_parts_override so batch analysis will apply it
          - Ready/analyzed files: immediately rewrites split_points with equal divisions

        This means the user can set parameters BEFORE or AFTER analysis.
        """
        selected_items = self.file_list.selectedItems()
        if not selected_items:
            # Nothing selected — apply to every file
            selected_items = [self.file_list.item(i)
                             for i in range(self.file_list.count())]

        if not selected_items:
            self._update_status("No files in list — add files first")
            return

        fixed_mode = self._parts_group.checkedId() == 1
        n = self.batch_n_parts.value() if fixed_mode else 0
        applied = 0

        for item in selected_items:
            filename = item.data(Qt.ItemDataRole.UserRole)
            job = self.jobs.get(filename)
            if not job:
                continue

            # Always store the override so analysis picks it up later
            job.n_parts_override = n

            # If already analyzed, apply immediately
            if job.status in ("ready", "done") and job.duration > 0:
                if fixed_mode and n >= 2:
                    step = job.duration / n
                    job.split_points = [
                        SplitPoint(timestamp=step * i, confidence=1.0, duration=0.0,
                                   label=f"Equal {i}/{n-1}")
                        for i in range(1, n)
                    ]
                    self._set_item_status(filename, "ready", len(job.split_points))
                applied += 1
            else:
                # Queued — mark visually so user knows the setting is staged
                applied += 1

        # Refresh editor for currently-selected file
        cur = self.file_list.currentItem()
        if cur:
            job = self.jobs.get(cur.data(Qt.ItemDataRole.UserRole))
            if job:
                self.split_editor.load_job(job)
                self._update_ep_count(job)

        if fixed_mode:
            self._update_status(
                f"Staged {n}-part split on {applied} file{'s' if applied != 1 else ''} "
                f"— will apply during analysis"
            )
        else:
            self._update_status(
                f"Reset {applied} file{'s' if applied != 1 else ''} to auto-detect"
            )

    def _update_file_count(self):
        n = len(self.jobs)
        self.file_count_label.setText(f"{n} file{'s' if n != 1 else ''}")

    # ── Settings change handlers ─────────────────────────────────────────────

    def _on_parts_mode_changed(self, btn_id: int, checked: bool):
        if not checked: return
        self.batch_n_parts.setEnabled(btn_id == 1)

    def _on_cut_mode_changed(self, btn_id: int, checked: bool):
        if not checked: return
        is_encode = btn_id in (1, 2)
        self._set_encoding_enabled(is_encode)
        msgs = {
            0: "Keyframe snap: lossless, cuts inside black frames",
            1: "Accurate re-encode: frame-exact cuts using Output Encoding settings",
            2: "Smart encode: re-encodes only the opening seconds of each split",
            3: "Stream copy: fastest — may start a few seconds before the cut",
        }
        self._update_status(msgs.get(btn_id, ""))

    def _set_encoding_enabled(self, encode_active: bool):
        self.out_container.setEnabled(True)
        self.audio_codec.setEnabled(True)
        for w in [self.video_codec, self.enc_speed, self.rb_crf,
                  self.rb_bitrate, self.crf_spin, self.bitrate_edit]:
            w.setEnabled(encode_active)
        if encode_active:
            self._on_quality_mode_changed(self._quality_mode_group.checkedId(), True)
            self._on_speed_changed()

    def _on_quality_mode_changed(self, btn_id: int, checked: bool):
        if not checked: return
        use_crf  = (btn_id == 0)
        lossless = self.enc_speed.currentText() == "Lossless"
        self.crf_spin.setEnabled(use_crf and not lossless)
        self.bitrate_edit.setEnabled(not use_crf and not lossless)

    def _on_codec_changed(self):
        txt = self.video_codec.currentText()
        if txt.startswith("Same"):
            self.crf_spin.setEnabled(False); self.enc_speed.setEnabled(False)
            self.rb_crf.setEnabled(False);   self.rb_bitrate.setEnabled(False)
            self.bitrate_edit.setEnabled(False); return
        else:
            lossless = self.enc_speed.currentText() == "Lossless"
            use_crf  = self._quality_mode_group.checkedId() == 0
            self.enc_speed.setEnabled(True)
            self.rb_crf.setEnabled(not lossless); self.rb_bitrate.setEnabled(not lossless)
            self.crf_spin.setEnabled(use_crf and not lossless)
            self.bitrate_edit.setEnabled(not use_crf and not lossless)
        if txt.startswith("H.264"):
            self.crf_spin.setToolTip("H.264 CRF: 18=high quality, 23=default")
        elif txt.startswith("H.265"):
            self.crf_spin.setToolTip("H.265 CRF: 24=high quality, 28=default")
            if self.crf_spin.value() == 18: self.crf_spin.setValue(24)
        elif txt.startswith("HEVC"):
            self.crf_spin.setToolTip("HEVC nvenc QP: 20=high quality, 28=default")
            if self.crf_spin.value() in (18, 24): self.crf_spin.setValue(20)
        elif txt.startswith("AV1"):
            self.crf_spin.setToolTip("AV1 CRF: 25=high quality, 35=default")
            if self.crf_spin.value() in (18, 24): self.crf_spin.setValue(25)

    def _on_speed_changed(self):
        lossless = self.enc_speed.currentText() == "Lossless"
        use_crf  = self._quality_mode_group.checkedId() == 0
        self.crf_spin.setEnabled(not lossless and use_crf)
        self.bitrate_edit.setEnabled(not lossless and not use_crf)
        self.rb_crf.setEnabled(not lossless)
        self.rb_bitrate.setEnabled(not lossless)

    def _on_file_selected(self, row):
        item = self.file_list.item(row)
        if not item: return
        job = self.jobs.get(item.data(Qt.ItemDataRole.UserRole))
        if not job: return
        self.split_editor.load_job(job)
        self.file_title.setText(job.filename)
        self._update_ep_count(job)
        self._refresh_splits_list(job)

    def _update_ep_count(self, job: VideoJob):
        if job.status == "queued":
            self.ep_count_label.setText("not analyzed")
            return
        enabled = sum(1 for sp in job.split_points if sp.enabled)
        eps = enabled + 1
        self.ep_count_label.setText(f"{eps} episode{'s' if eps != 1 else ''}")

    def _on_splits_changed(self):
        item = self.file_list.currentItem()
        if item:
            job = self.jobs.get(item.data(Qt.ItemDataRole.UserRole))
            if job:
                self._update_ep_count(job)
                self._refresh_splits_list(job)

    def _refresh_splits_list(self, job: VideoJob):
        """Rebuild the split-points panel with one editable row per break."""
        # Clear existing rows (leave the trailing stretch)
        while self._splits_layout.count() > 1:
            item = self._splits_layout.takeAt(0)
            if item.widget():
                item.widget().deleteLater()

        enabled = [sp for sp in job.split_points if sp.enabled]

        if not enabled:
            self.splits_empty.show()
            self._splits_container.hide()
            self.splits_empty.setText(
                "No breaks detected" if job.status == "ready"
                else "Analyze file to see break points"
            )
            self.ep_count_label.setText("")
            return

        self.splits_empty.hide()
        self._splits_container.show()

        for i, sp in enumerate(enabled):
            self._splits_layout.insertWidget(i, self._make_split_row(sp, job))

        eps = len(enabled) + 1
        self.ep_count_label.setText(f"{eps} part{'s' if eps != 1 else ''}")

    def _make_split_row(self, sp: SplitPoint, job: VideoJob) -> QFrame:
        """One row: [✂ timecode]  [Edit]  [✕]"""
        row = QFrame(); row.setObjectName("splitRow")
        lay = QHBoxLayout(row); lay.setContentsMargins(10, 4, 6, 4); lay.setSpacing(6)

        icon = QLabel("✂"); icon.setObjectName("splitIcon")
        icon.setFixedWidth(14)
        lay.addWidget(icon)

        ts_lbl = QLabel(fmt_time(sp.timestamp))
        ts_lbl.setObjectName("splitTimecode")
        ts_lbl.setFixedWidth(68)
        lay.addWidget(ts_lbl)

        conf = int(sp.confidence * 100)
        if conf < 100:
            conf_lbl = QLabel(f"{conf}%")
            conf_lbl.setObjectName("splitConf")
            lay.addWidget(conf_lbl)

        lay.addStretch()

        edit_btn = QPushButton("Edit")
        edit_btn.setObjectName("splitEditBtn")
        edit_btn.setFixedWidth(38)
        edit_btn.clicked.connect(lambda _, s=sp, j=job: self._edit_split(s, j))
        lay.addWidget(edit_btn)

        del_btn = QPushButton("✕")
        del_btn.setObjectName("splitDelBtn")
        del_btn.setFixedWidth(26)
        del_btn.clicked.connect(lambda _, s=sp, j=job: self._delete_split(s, j))
        lay.addWidget(del_btn)

        return row

    def _edit_split(self, sp: SplitPoint, job: VideoJob):
        """Show inline edit — replace timecode label with a QLineEdit."""
        from PyQt6.QtWidgets import QInputDialog
        current = fmt_time(sp.timestamp)
        new_ts_str, ok = QInputDialog.getText(
            self, "Edit Split Point",
            f"Current: {current}\n\nEnter new time (MM:SS  or  HH:MM:SS  or  seconds):",
            text=current
        )
        if not ok or not new_ts_str.strip():
            return
        try:
            raw = new_ts_str.strip()
            if ":" in raw:
                parts = raw.replace(",", ".").split(":")
                ts = (int(parts[0])*3600 + int(parts[1])*60 + float(parts[2])
                      if len(parts) == 3 else int(parts[0])*60 + float(parts[1]))
            else:
                ts = float(raw)
        except ValueError:
            return
        sp.timestamp = ts
        sp.label     = f"Manual at {fmt_time(ts)}"
        sp.confidence = 1.0
        job.split_points.sort(key=lambda x: x.timestamp)
        self._refresh_splits_list(job)
        self._update_ep_count(job)

    def _delete_split(self, sp: SplitPoint, job: VideoJob):
        """Remove a split point and refresh the list."""
        if sp in job.split_points:
            job.split_points.remove(sp)
        self._refresh_splits_list(job)
        self._update_ep_count(job)

    def _add_manual_split(self):
        """Add a manual split point from the time input box."""
        item = self.file_list.currentItem()
        if not item: return
        job = self.jobs.get(item.data(Qt.ItemDataRole.UserRole))
        if not job: return
        raw = self.time_input.text().strip()
        try:
            if ":" in raw:
                parts = raw.replace(",", ".").split(":")
                ts = (int(parts[0])*3600 + int(parts[1])*60 + float(parts[2])
                      if len(parts) == 3 else int(parts[0])*60 + float(parts[1]))
            else:
                ts = float(raw)
        except Exception:
            return
        job.split_points.append(SplitPoint(
            timestamp=ts, confidence=1.0, duration=0.0,
            label=f"Manual at {fmt_time(ts)}"
        ))
        job.split_points.sort(key=lambda x: x.timestamp)
        self.time_input.clear()
        self._refresh_splits_list(job)
        self._update_ep_count(job)

    def _open_naming_dialog(self):
        if not HAS_NAMING:
            QMessageBox.warning(self, "Not Available",
                "naming_dialog.py not found next to episode_splitter.py")
            return
        if not self.jobs:
            QMessageBox.information(self, "No Files", "Add video files first.")
            return
        settings = self._settings()
        settings["tmdb_api_key"] = self._tmdb_api_key
        settings["tvdb_api_key"] = self._tvdb_api_key
        dlg = EpisodeNamingDialog(list(self.jobs.values()), settings, self)
        dlg.confirmed.connect(self._on_naming_confirmed)
        dlg.exec()

    def _on_naming_confirmed(self, plans: list):
        """Store confirmed naming plans; applied during _split_file."""
        self._naming_plans = {p.job_filename: p for p in plans}
        self._log(f"Episode names confirmed for {len(plans)} file(s)")
        # Save API keys for next time
        if plans:
            from naming_dialog import EpisodeNamingDialog as _D
        self._update_status(
            f"✓ Episode names set for {len(plans)} file(s) — ready to split"
        )

    def _pick_output(self):
        d = QFileDialog.getExistingDirectory(self, "Choose Output Folder")
        if d:
            self.output_dir = d
            short = d if len(d) < 45 else "..." + d[-42:]
            self.out_label.setText(f"Output: {short}")
            for job in self.jobs.values(): job.output_dir = d

    def _settings(self) -> dict:
        mode_map = {0: "keyframe_snap", 1: "accurate", 2: "smart", 3: "stream_copy"}
        cut_mode = mode_map.get(self._cut_mode_group.checkedId(), "keyframe_snap")

        # Container mapping
        container_map = {
            "Same as source": "source",
            "MP4 (.mp4)":     "mp4",
            "MKV (.mkv)":     "mkv",
        }
        out_container = container_map.get(self.out_container.currentText(), "source")

        # Video codec mapping
        # Match by prefix so the descriptive text after the codec name doesn't matter
        _vt = self.video_codec.currentText()
        if   _vt.startswith("Same"):   video_codec = "copy"
        elif _vt.startswith("H.264"):  video_codec = "libx264"
        elif _vt.startswith("H.265"):  video_codec = "libx265"
        elif _vt.startswith("HEVC"):   video_codec = "hevc_nvenc"
        elif _vt.startswith("AV1"):    video_codec = "libsvtav1"
        else:                          video_codec = "libx264"

        # Audio codec mapping
        audio_map = {
            "AAC":                "aac",
            "AC3 (Dolby)":       "ac3",
            "Copy (no re-encode)": "copy",
        }
        audio_codec = audio_map.get(self.audio_codec.currentText(), "aac")

        # Speed -> FFmpeg preset mapping per codec
        speed_label = self.enc_speed.currentText()
        lossless    = (speed_label == "Lossless")

        preset_map_x264_x265 = {
            "Lossless":  "medium",    # overridden by lossless flag
            "Ultra Fast": "ultrafast",
            "Very Fast":  "veryfast",
            "Fast":       "fast",
            "Medium":     "medium",
            "Slow":       "slow",
            "Very Slow":  "veryslow",
        }
        # AV1 (libsvtav1) uses numeric presets 0-13
        preset_map_av1 = {
            "Lossless":   "8",
            "Ultra Fast": "12",
            "Very Fast":  "10",
            "Fast":       "8",
            "Medium":     "6",
            "Slow":       "4",
            "Very Slow":  "2",
        }
        if video_codec == "libsvtav1":
            preset = preset_map_av1.get(speed_label, "8")
        else:
            preset = preset_map_x264_x265.get(speed_label, "fast")

        # Quality mode
        use_crf     = self._quality_mode_group.checkedId() == 0
        crf_value   = self.crf_spin.value()
        bitrate_str = self.bitrate_edit.text().strip()
        try:
            bitrate_kbps = int(bitrate_str) if bitrate_str else 0
        except ValueError:
            bitrate_kbps = 0

        return {
            # Detection
            "black_min_duration": self.black_dur.value(),
            "pixel_threshold":    self.pix_th.value(),
            "picture_threshold":  self.pic_th.value(),
            # Cut mode
            "cut_mode":           cut_mode,
            "accurate_cuts":      (cut_mode == "accurate"),
            # Output encoding
            "out_container":      out_container,
            "video_codec":        video_codec,
            "audio_codec":        audio_codec,
            "preset":             preset,
            "lossless":           lossless,
            "use_crf":            use_crf,
            "crf":                crf_value,
            "bitrate_kbps":       bitrate_kbps,
        }

    def _log(self, msg: str):
        self.log_view.append(msg)
        self.log_view.verticalScrollBar().setValue(self.log_view.verticalScrollBar().maximum())

    def _show_progress(self, pct: int):
        """Show progress bar and percentage label, update both."""
        self.progress_bar.setValue(pct)
        self.progress_bar.show()
        self.pct_label.setText(f"{pct}%")
        self.pct_label.show()
        # Don't call _restore here — would fight with every progress update tick

    def _hide_progress(self):
        """Hide progress bar and percentage label."""
        self.progress_bar.hide()
        self.pct_label.hide()

    def _set_buttons_busy(self, busy: bool):
        self.batch_btn.setEnabled(not busy)
        self.batch_analyze_btn.setEnabled(not busy)
        self.analyze_btn.setEnabled(not busy)
        if not busy:
            ready = any(j.status == "ready" for j in self.jobs.values())
            self.split_btn.setEnabled(ready)
        else:
            self.split_btn.setEnabled(False)

    # ── BATCH MODE ────────────────────────────

    def _start_batch(self):
        """Analyze all queued files then automatically split them."""
        if not self.jobs:
            QMessageBox.information(self, "No Files", "Add video files first."); return
        if not self.manager.get_info():
            QMessageBox.warning(self, "FFmpeg Missing",
                "FFmpeg is not installed.\nOpen the FFmpeg Manager to download it."); return

        self._batch_mode = True
        self._log("=== BATCH MODE: Analyze + Split All ===")
        self._start_analysis()

    # ── ANALYSIS ─────────────────────────────

    def _start_analysis(self):
        try:
            if not self.jobs:
                QMessageBox.information(self, "No Files", "Add video files first.")
                return

            # Ensure FFmpeg is located (re-try if startup check hasn't finished)
            info = self.manager.get_info()
            if not info:
                info = self.manager.locate()
            if not info:
                QMessageBox.warning(self, "FFmpeg Missing",
                    "FFmpeg is not installed.\nOpen the FFmpeg Manager to download it.")
                return

            self._log(f"FFmpeg:  {info.path}")
            self._log(f"FFprobe: {info.probe_path}")

            queued = [j for j in self.jobs.values() if j.status in ("queued", "error")]
            if not queued:
                queued = list(self.jobs.values())

            self._log(f"Analyzing {len(queued)} file(s)...")
            self._set_buttons_busy(True)
            self._show_progress(0)
            self._update_status(f"Analyzing {len(queued)} file(s)...")

            for job in queued:
                job.status = "analyzing"
                self._set_item_status(job.filename, "analyzing")

            try:
                settings = self._settings()
            except Exception as e:
                self._log(f"[ERROR] Reading settings failed: {e}")
                self._set_buttons_busy(False)
                return

            self.analysis_worker = AnalysisWorker(queued, settings, self.manager)
            self.analysis_worker.split_found.connect(self._on_analysis_done)
            self.analysis_worker.progress.connect(lambda fn, p: self._show_progress(p))
            self.analysis_worker.log_message.connect(self._log)
            self.analysis_worker.error.connect(self._on_analysis_error)
            self.analysis_worker.finished.connect(self._on_all_analysis_done)
            self.analysis_worker.start()

        except Exception as e:
            import traceback
            self._log(f"[ERROR] _start_analysis crashed: {e}")
            self._log(traceback.format_exc())
            self._set_buttons_busy(False)


    def _on_analysis_done(self, filename: str, splits: list, streams: dict, duration: float, fsize: int):
        try:
            job = self.jobs.get(filename)
            if not job:
                self._log(f"  [WARN] _on_analysis_done: no job found for '{filename}'")
                return
            job.split_points    = splits
            job.streams         = streams
            job.duration        = duration
            job.file_size_bytes = fsize
            job.status          = "ready"


            # N-parts override: "Split into N parts" = keep first N-1 detected splits.
            # e.g. N=2 → keep only the FIRST detected black frame → 2 output files.
            # This does NOT create equal-time divisions.
            try:
                n = job.n_parts_override
                if n == 0 and hasattr(self, '_parts_group') and hasattr(self, 'batch_n_parts'):
                    n = self.batch_n_parts.value() if self._parts_group.checkedId() == 1 else 0
                if n >= 2:
                    original_count = len(job.split_points)
                    job.split_points = job.split_points[:n - 1]
                    self._log(f"  Split count={n}: keeping first {len(job.split_points)} of {original_count} detected break(s)")
            except Exception as e:
                self._log(f"  [WARN] N-parts failed (non-fatal): {e}")

            self._set_item_status(filename, "ready", len(job.split_points))
            item = self.file_list.currentItem()
            if item and item.data(Qt.ItemDataRole.UserRole) == filename:
                self.split_editor.load_job(job)
                self._update_ep_count(job)
                self._refresh_splits_list(job)
        except Exception as e:
            import traceback
            self._log(f"  [ERROR] _on_analysis_done crashed: {e}")
            self._log(traceback.format_exc())

    def _on_analysis_error(self, filename: str, msg: str):
        job = self.jobs.get(filename)
        if job: job.status = "error"
        self._set_item_status(filename, "error")
        self._log(f"ERROR analyzing {filename}: {msg}")

    def _on_all_analysis_done(self):
        try:
            statuses = {j.filename: j.status for j in self.jobs.values()}
            self._log(f"Analysis thread finished. Job statuses: {statuses}")
            n = sum(1 for s in statuses.values() if s == "ready")
            self._update_status(f"Analysis complete — {n} file(s) ready")
            self._log(f"Analysis complete. {n} file(s) ready.")
            self._hide_progress()

            if self._batch_mode:
                if n == 0:
                    self._log("Batch: no files are ready — check errors above.")
                    self._set_buttons_busy(False)
                    self._batch_mode = False
                    return
                self._log(f"Batch: starting split of {n} file(s)...")
                QTimer.singleShot(50, self._start_split)
            else:
                self._set_buttons_busy(False)
        except Exception as e:
            import traceback
            self._log(f"[ERROR] _on_all_analysis_done: {e}")
            self._log(traceback.format_exc())
            self._set_buttons_busy(False)

    # ── SPLITTING ─────────────────────────────

    def _start_split(self):
        try:
            ready = [j for j in self.jobs.values() if j.status == "ready"]
            self._log(f"_start_split: {len(ready)} ready job(s): {[j.filename for j in ready]}")
            if not ready:
                self._log(f"All statuses: { {j.filename: j.status for j in self.jobs.values()} }")
                QMessageBox.information(self, "Not Ready",
                    "No files are ready to split.\nRun Analyze first.")
                return

            if self.output_dir:
                for job in ready:
                    job.output_dir = self.output_dir

            self._set_buttons_busy(True)
            self._show_progress(0)
            self._update_status(f"Splitting {len(ready)} file(s)...")
            self._log(f"Splitting {len(ready)} file(s)...")

            for job in ready:
                job.status = "splitting"
                self._set_item_status(job.filename, "splitting")

            try:
                settings = self._settings()
            except Exception as e:
                self._log(f"[ERROR] Reading settings for split failed: {e}")
                self._set_buttons_busy(False)
                return

            # Set output_dir on each job so we can find files after splitting
            out_base = self.output_dir
            for job in ready:
                if not job.output_dir:
                    job.output_dir = out_base or str(Path(job.path).parent / "episodes")
                plan = self._naming_plans.get(job.filename)
                if plan:
                    job._naming_plan = plan
            self.split_worker = SplitWorker(ready, settings, self.manager)
            self.split_worker.progress.connect(lambda fn, p, m: (
                self._show_progress(p), self._update_status(f"{fn}: {m}")
            ))
            self.split_worker.done.connect(self._on_split_done)
            self.split_worker.error.connect(self._on_split_error)
            self.split_worker.log_message.connect(self._log)
            self.split_worker.finished.connect(self._on_all_split_done)
            self.split_worker.start()
        except Exception as e:
            import traceback
            self._log(f"[ERROR] _start_split crashed: {e}")
            self._log(traceback.format_exc())
            self._set_buttons_busy(False)


    def _on_split_done(self, filename: str, num_eps: int):
        job = self.jobs.get(filename)
        if job: job.status = "done"
        self._set_item_status(filename, "done", num_eps)
        self._log(f"Done: {filename} -> {num_eps} episode(s)")

    def _on_split_error(self, filename: str, msg: str):
        job = self.jobs.get(filename)
        if job: job.status = "error"
        self._set_item_status(filename, "error")
        self._log(f"ERROR splitting {filename}: {msg}")

    def _on_all_split_done(self):
        self._batch_mode = False
        self._hide_progress()
        done = sum(1 for j in self.jobs.values() if j.status == "done")
        err  = sum(1 for j in self.jobs.values() if j.status == "error")
        self._update_status(f"Done! {done} file(s) split successfully." +
                            (f" {err} error(s)." if err else ""))
        self._log(f"All done. {done} split, {err} error(s).")
        self._set_buttons_busy(False)

        # Collect all unique output dirs from completed jobs
        out_dirs = list(dict.fromkeys(
            j.output_dir for j in self.jobs.values()
            if j.status == "done" and j.output_dir
        ))
        if not out_dirs:
            out_dirs = [str(Path(j.path).parent / "episodes")
                        for j in self.jobs.values() if j.status == "done"]
        primary_out = out_dirs[0] if out_dirs else ""

        # Auto-open rename dialog if checkbox is ticked
        if hasattr(self, "rename_cb") and self.rename_cb.isChecked() and primary_out and done > 0:
            self._log(f"Rename checkbox active — opening naming dialog for: {primary_out}")
            QTimer.singleShot(300, lambda: self._open_post_split_naming(primary_out))
            return

        msg = f"Successfully split {done} file(s)!"
        if primary_out:
            msg += f"\n\nOutput folder:\n{primary_out}"
        if err:
            msg += f"\n\n{err} file(s) had errors — check the log for details."
        QMessageBox.information(self, "Complete", msg)

    def _open_post_split_naming(self, out_dir: str):
        """
        Open naming dialog with all freshly-split output files pre-loaded.
        Auto-triggers a show search from the original source filename.
        """
        import os as _os
        if not HAS_NAMING:
            QMessageBox.warning(self, "Not Available",
                "naming_dialog.py is missing — cannot open rename dialog.")
            return

        VIDEO_EXT = {".mp4", ".mkv", ".avi", ".mov", ".ts", ".m2ts"}
        try:
            out_files = sorted([
                f for f in _os.listdir(out_dir)
                if _os.path.splitext(f)[1].lower() in VIDEO_EXT
            ])
        except Exception as e:
            self._log(f"[WARN] Cannot read output folder {out_dir}: {e}")
            out_files = []

        if not out_files:
            QMessageBox.information(self, "Rename Output",
                f"No video files found in:\n{out_dir}\n\n"
                "Make sure the split completed successfully.")
            return

        fake_jobs = []
        for fn in out_files:
            full = _os.path.join(out_dir, fn)
            ext  = _os.path.splitext(fn)[1].lstrip(".") or "mkv"
            fake_jobs.append(VideoJob(path=full, filename=fn,
                                      status="done", container=ext))

        self._log(f"Rename dialog: {len(fake_jobs)} output file(s) from {out_dir}")

        try:
            settings = self._settings()
        except Exception:
            settings = {}
        settings["tmdb_api_key"] = self._tmdb_api_key
        settings["tvdb_api_key"] = self._tvdb_api_key

        dlg = EpisodeNamingDialog(fake_jobs, settings, self)
        dlg.confirmed.connect(lambda plans: self._apply_rename(plans, out_dir))

        # Auto-search using the first original source filename
        first_src = next(
            (j.filename for j in self.jobs.values() if j.status == "done"), None
        )
        if first_src:
            QTimer.singleShot(500, lambda: dlg._auto_detect_from(first_src))

        dlg.exec()

    def _apply_rename(self, plans: list, out_dir: str):
        """Physically rename output files based on confirmed naming plans."""
        import os as _os
        renamed = 0
        errors  = []
        for plan in plans:
            if not plan.confirmed or not plan.output_names:
                continue
            old_path = _os.path.join(out_dir, plan.job_filename)
            new_name = plan.output_names[0]   # one name per output file
            new_path = _os.path.join(out_dir, new_name)
            if old_path == new_path:
                continue
            try:
                _os.rename(old_path, new_path)
                self._log(f"  Renamed: {plan.job_filename} → {new_name}")
                renamed += 1
            except Exception as e:
                errors.append(f"{plan.job_filename}: {e}")
        msg = f"Renamed {renamed} file(s)."
        if errors:
            msg += "\n\nErrors:\n" + "\n".join(errors)
        QMessageBox.information(self, "Rename Complete", msg)

    # ── HELPERS ───────────────────────────────

    def _set_item_status(self, filename: str, status: str, count: int = 0):
        ICONS  = {"queued":"○","analyzing":"◌","ready":"◉","splitting":"◈","done":"✓","error":"✗"}
        COLORS = {"queued":"#64748b","analyzing":"#fb923c","ready":"#38bdf8",
                  "splitting":"#a78bfa","done":"#4ade80","error":"#f87171"}
        for i in range(self.file_list.count()):
            item = self.file_list.item(i)
            if item.data(Qt.ItemDataRole.UserRole) == filename:
                suffix = (f" ({count} break{'s' if count != 1 else ''})"
                          if count and status == "ready" else "")
                item.setText(f"  {ICONS.get(status,'○')}  {filename}{suffix}")
                item.setForeground(QColor(COLORS.get(status,"#64748b")))
                break

    def _update_status(self, msg: str):
        self.status_label.setText(msg)

